import styled from 'styled-components';

export const SkillsContainer = styled.section`
background: rgba(80,96,216, 1);
height:100%;
margin:0;

    .title {
        display:block;
        position:absolute;
        top:52em;
        right:40%;
        text-align: center;
        background:rgba(80,96,216, 1);
        border:1px solid rgba(80,96,216, 1);
        width: 25em;
        height: 3.25em;
        z-index:2;
    }


`
